'use client';

import { useState, useEffect, useCallback } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Trash2, RefreshCw, FileText, AlertCircle, Download } from 'lucide-react';
import { toast } from 'sonner';

interface LogData {
  logs: string[];
  lines: number;
  size: number;
  type: 'app' | 'error';
}

export default function LogsPage() {
  const [logData, setLogData] = useState<LogData | null>(null);
  const [logType, setLogType] = useState<'app' | 'error'>('app');
  const [lines, setLines] = useState(100);
  const [loading, setLoading] = useState(false);
  const [autoRefresh, setAutoRefresh] = useState(false);

  const fetchLogs = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(`/api/logs?type=${logType}&lines=${lines}`);
      const data = await res.json();
      if (data.success) {
        setLogData(data.data);
      } else {
        toast.error(data.error || 'Failed to fetch logs');
      }
    } catch (err) {
      toast.error('Failed to fetch logs');
    } finally {
      setLoading(false);
    }
  }, [logType, lines]);

  useEffect(() => {
    fetchLogs();
  }, [fetchLogs]);

  useEffect(() => {
    if (autoRefresh) {
      const interval = setInterval(fetchLogs, 3000);
      return () => clearInterval(interval);
    }
  }, [autoRefresh, fetchLogs]);

  const handleClearLogs = async () => {
    try {
      const res = await fetch('/api/logs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'clear', type: logType }),
      });
      const data = await res.json();
      if (data.success) {
        toast.success('Logs cleared');
        fetchLogs();
      } else {
        toast.error(data.error || 'Failed to clear logs');
      }
    } catch (err) {
      toast.error('Failed to clear logs');
    }
  };

  const handleDownloadLogs = () => {
    if (!logData) return;
    const content = logData.logs.join('\n');
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `dyrec-${logType}-log.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const formatSize = (bytes: number): string => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  };

  const getLogColor = (line: string): string => {
    if (line.includes('[ERROR]')) return 'text-red-400';
    if (line.includes('[WARN]')) return 'text-amber-400';
    if (line.includes('[INFO]')) return 'text-cyan-400';
    if (line.includes('[DEBUG]')) return 'text-zinc-400';
    return 'text-zinc-300';
  };

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-zinc-100">系统日志</h1>
          <p className="text-zinc-500">查看应用运行日志，便于排查问题</p>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant={autoRefresh ? 'default' : 'outline'} className="cursor-pointer" onClick={() => setAutoRefresh(!autoRefresh)}>
            {autoRefresh ? '自动刷新: 开' : '自动刷新: 关'}
          </Badge>
        </div>
      </div>

      <Card className="bg-zinc-900/50 border-zinc-800">
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                <span className="text-sm text-zinc-400">日志类型:</span>
                <Select value={logType} onValueChange={(v) => setLogType(v as 'app' | 'error')}>
                  <SelectTrigger className="w-32 bg-zinc-800 border-zinc-700">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="app">应用日志</SelectItem>
                    <SelectItem value="error">错误日志</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-sm text-zinc-400">行数:</span>
                <Select value={String(lines)} onValueChange={(v) => setLines(parseInt(v))}>
                  <SelectTrigger className="w-24 bg-zinc-800 border-zinc-700">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="50">50</SelectItem>
                    <SelectItem value="100">100</SelectItem>
                    <SelectItem value="200">200</SelectItem>
                    <SelectItem value="500">500</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              {logData && (
                <div className="flex items-center gap-2 text-sm text-zinc-500">
                  <FileText className="w-4 h-4" />
                  <span>{logData.lines} 行</span>
                  <span>•</span>
                  <span>{formatSize(logData.size)}</span>
                </div>
              )}
            </div>
            <div className="flex items-center gap-2">
              <Button variant="outline" size="sm" onClick={fetchLogs} disabled={loading}>
                <RefreshCw className={`w-4 h-4 mr-1 ${loading ? 'animate-spin' : ''}`} />
                刷新
              </Button>
              <Button variant="outline" size="sm" onClick={handleDownloadLogs}>
                <Download className="w-4 h-4 mr-1" />
                下载
              </Button>
              <Button variant="destructive" size="sm" onClick={handleClearLogs}>
                <Trash2 className="w-4 h-4 mr-1" />
                清空
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="bg-black/50 rounded-lg p-4 h-[600px] overflow-auto font-mono text-xs">
            {logData && logData.logs.length > 0 ? (
              logData.logs.map((line, index) => (
                <div key={index} className={`${getLogColor(line)} whitespace-pre-wrap break-all`}>
                  {line}
                </div>
              ))
            ) : (
              <div className="flex items-center justify-center h-full text-zinc-500">
                <AlertCircle className="w-5 h-5 mr-2" />
                暂无日志
              </div>
            )}
          </div>
        </CardContent>
      </Card>

      <Card className="bg-zinc-900/50 border-zinc-800">
        <CardHeader>
          <CardTitle className="text-lg">日志说明</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-2 text-sm text-zinc-400">
            <div className="flex items-center gap-2">
              <span className="text-red-400 font-mono">[ERROR]</span>
              <span>错误日志 - 记录系统错误和异常</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-amber-400 font-mono">[WARN]</span>
              <span>警告日志 - 记录潜在问题和注意事项</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-cyan-400 font-mono">[INFO]</span>
              <span>信息日志 - 记录系统运行状态</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-zinc-400 font-mono">[DEBUG]</span>
              <span>调试日志 - 记录详细调试信息</span>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}
